private observeElement(force = false) {
    if (this.observer === undefined) {
        return;
    }

    if (!(this.targetRef.current instanceof Element)) {
        // stop everything if not defined
        this.observer.disconnect();
        return;
    }

    if (this.targetRef.current === this.prevElement && !force) {
        // quit if given same element -- nothing to update (unless forced)
        return;
    } else {
        // clear observer list if new element
        this.observer.disconnect();
        // remember element reference for next time
        this.prevElement = this.targetRef.current;
    }

    // observer callback is invoked immediately when observing new elements
    this.observer.observe(this.targetRef.current);

    if (this.props.observeParents) {
        let parent = this.targetRef.current.parentElement;
        while (parent != null) {
            this.observer.observe(parent);
            parent = parent.parentElement;
        }
    }
}

(event: React.UIEvent<HTMLElement>) => {
    if (this.wasMainQuadrantScrollTriggeredByWheelEvent) {
        this.wasMainQuadrantScrollTriggeredByWheelEvent = false;
        return;
    }

    const mainScrollContainer = this.quadrantRefs[QuadrantType.MAIN].scrollContainer;
    if (mainScrollContainer == null) {
        return;
    }

    // invoke onScroll - which may read current scroll position - before
    // forcing a reflow with upcoming .scroll{Top,Left} setters.
    this.props.onScroll?.(event);

    // batch DOM reads here. note that onScroll events don't include deltas
    // like onWheel events do, so we have to read from the DOM directly.
    const nextScrollLeft = mainScrollContainer.scrollLeft;
    const nextScrollTop = mainScrollContainer.scrollTop;

    // with the "scroll" event, scroll offsets are updated prior to the
    // event's firing, so no explicit update needed.
    this.handleScrollOffsetChange("scrollLeft", nextScrollLeft);
    this.handleScrollOffsetChange("scrollTop", nextScrollTop);

    // sync less important view stuff when scrolling/wheeling stops.
    this.syncQuadrantViewsDebounced();
}

(
  chartEvent: RelativePointer | undefined,
  layout: CartesianLayout,
  tooltipAxisType: AxisType | undefined,
  tooltipAxisRange: AxisRange | undefined,
  tooltipTicks: ReadonlyArray<TickItem> | undefined,
  orderedTooltipTicks: ReadonlyArray<TickItem> | undefined,
  offset: ChartOffsetInternal,
): ActiveTooltipProps | undefined => {
  if (!chartEvent || !tooltipAxisType || !tooltipAxisRange || !tooltipTicks) {
    return undefined;
  }
  if (!isInCartesianRange(chartEvent, offset)) {
    return undefined;
  }
  const pos: number | undefined = calculateCartesianTooltipPos(chartEvent, layout);

  const activeIndex = calculateActiveTickIndex(
    pos,
    orderedTooltipTicks,
    tooltipTicks,
    tooltipAxisType,
    tooltipAxisRange,
  );

  const activeCoordinate = getActiveCartesianCoordinate(layout, tooltipTicks, activeIndex, chartEvent);

  return { activeIndex: String(activeIndex), activeCoordinate };
}

async function getManifestRoute(
  route: RSCRouteConfigEntry & { parentId: string | undefined },
): Promise<RSCRouteManifest> {
  await explodeLazyRoute(route);

  const Layout = (route as any).Layout || React.Fragment;
  // We send errorElement early in the manifest so we have it client
  // side for any client-side errors thrown during dataStrategy
  const errorElement = route.ErrorBoundary
    ? React.createElement(
        Layout,
        null,
        React.createElement(route.ErrorBoundary),
      )
    : undefined;

  return {
    clientAction: route.clientAction,
    clientLoader: route.clientLoader,
    handle: route.handle,
    hasAction: !!route.action,
    hasComponent: !!route.Component,
    hasErrorBoundary: !!route.ErrorBoundary,
    errorElement,
    hasLoader: !!route.loader,
    id: route.id,
    parentId: route.parentId,
    path: route.path,
    index: "index" in route ? route.index : undefined,
    links: route.links,
    meta: route.meta,
  };
}

(file, api) => {
  const jscodeshift = api.jscodeshift
  const root = jscodeshift(file.source)

  // TODO: Execute the transformers only when it contains a `react-query` import!

  const utils = createUtilsObject({ root, jscodeshift })
  const filePath = file.path
  const packageName = 'react-query'

  // This function transforms usages like `useQuery` and `useMutation`.
  transformUseQueryLikeUsages({
    jscodeshift,
    utils,
    root,
    filePath,
    packageName,
  })
  // This function transforms usages of `useQueries`.
  transformUseQueriesUsages({
    jscodeshift,
    utils,
    root,
    packageName,
  })
  // This function transforms usages of `QueryClient`.
  transformQueryClientUsages({
    jscodeshift,
    utils,
    root,
    filePath,
    packageName,
  })
  // This function transforms usages of `QueryCache`.
  transformQueryCacheUsages({ jscodeshift, utils, root, filePath, packageName })

  return root.toSource({ quote: 'single', lineTerminator: '\n' })
}

async function generatePackageReferenceDocs(pkg: PackageReferenceDocsConfig) {
  const outputDir = pkg.outputDir
  await rm(outputDir, { recursive: true, force: true })
  await mkdir(outputDir, { recursive: true })

  const app = await TypeDoc.Application.bootstrapWithPlugins({
    plugin: [
      'typedoc-plugin-markdown',
      'typedoc-plugin-frontmatter',
      resolve(typedocConfigDir, './src/typedoc-custom-settings.js'),
    ],
    hideGenerator: true,
    readme: 'none',
    entryFileName: 'index',
    hideBreadcrumbs: true,
    hidePageHeader: true,
    useCodeBlocks: true,
    excludePrivate: true,
    excludeInternal: true,
    excludeExternals: pkg.excludeExternals,
    sourceLinkTemplate:
      'https://github.com/TanStack/query/blob/{gitRevision}/{path}#L{line}',
    gitRevision: 'main',
    entryPoints: pkg.entryPoints,
    tsconfig: pkg.tsconfig,
    exclude: pkg.exclude,
    out: outputDir,
  })

  const project = await app.convert()

  if (project) {
    if (pkg.simplifyLitQueriesControllerTypes) {
      simplifyLitQueriesControllerTypes(project)
    }

    await app.generateOutputs(project)

    if (pkg.trimGeneratedMarkdown) {
      await trimTrailingWhitespaceInMarkdown(outputDir)
    }
  }
}

function createCompositeHandle(
  flightStream: ReadableStream<Uint8Array>,
  options?: {
    slotUsagesStream?: ReadableStream<RscSlotUsageEvent>
  },
): AnyCompositeComponent {
  // Simple single-use stream wrapper. For server function calls, the stream
  // is consumed exactly once by the serialization adapter for transport.
  const streamWrapper: ServerComponentStream = {
    createReplayStream: () => flightStream,
  }

  // Create a stub function with the stream attached for serialization.
  // This will never be rendered directly - it goes through serialization
  // which extracts the stream and sends it to the client.
  const stub = function CompositeComponentStub(): never {
    throw new Error(
      'CompositeComponent from server function cannot be rendered on server. ' +
        'It should be serialized and sent to the client.',
    )
  }

  ;(stub as any)[SERVER_COMPONENT_STREAM] = streamWrapper
  // Note: RENDERABLE_RSC is not set (or implicitly false), indicating this is a composite component

  if (options?.slotUsagesStream) {
    ;(stub as any)[RSC_SLOT_USAGES_STREAM] = options.slotUsagesStream
  }

  return stub as unknown as AnyCompositeComponent
}

export function createRscCssCompilerTransforms(opts: {
  loadCssExpression: string
  serverFnProviderOnly?: boolean | undefined
}): Array<StartCompilerImportTransform> {
  let loadCssExpression: BabelExpression | undefined

  const getLoadCssExpression = (context: StartCompilerTransformContext) => {
    loadCssExpression ??= context.parseExpression(opts.loadCssExpression)
    return loadCssExpression
  }

  return [
    createRscCssCompilerTransform({
      serverFnProviderOnly: opts.serverFnProviderOnly,
      getLoadCssExpression,
      kind: 'renderServerComponent',
      name: 'react-rsc-render-server-component-css',
    }),
    createRscCssCompilerTransform({
      serverFnProviderOnly: opts.serverFnProviderOnly,
      getLoadCssExpression,
      kind: 'createCompositeComponent',
      name: 'react-rsc-create-composite-component-css',
    }),
    createRscCssCompilerTransform({
      serverFnProviderOnly: opts.serverFnProviderOnly,
      getLoadCssExpression,
      kind: 'renderToReadableStream',
      name: 'react-rsc-render-to-readable-stream-css',
    }),
  ]
}

function configureRscRsbuild(): {
  providerEnvironmentName: TanStackStartRsbuildPluginCoreOptions['providerEnvironmentName']
  serializationAdapters: TanStackStartRsbuildPluginCoreOptions['serializationAdapters']
  compilerTransforms: TanStackStartRsbuildPluginCoreOptions['compilerTransforms']
  serverFnProviderModuleDirectives: TanStackStartRsbuildPluginCoreOptions['serverFnProviderModuleDirectives']
} {
  return {
    providerEnvironmentName: RSBUILD_ENVIRONMENT_NAMES.server,
    serializationAdapters: [
      {
        client: {
          module: '@tanstack/react-start/rsc/serialization/client',
          export: 'rscSerializationAdapter',
          isFactory: true,
        },
        server: {
          module: '@tanstack/react-start/rsc/serialization/server',
          export: 'rscSerializationAdapter',
          isFactory: true,
        },
      },
    ],
    compilerTransforms: createRscCssCompilerTransforms({
      loadCssExpression: 'import.meta.rspackRsc.loadCss()',
      serverFnProviderOnly: true,
    }),
    serverFnProviderModuleDirectives: ['use server-entry'],
  }
}
